#pragma once

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <cuda.h>

#include <torch/extension.h>
#include <torch/types.h>

// Constants for the kernel
constexpr int HIDDEN_SIZE = 4096;
constexpr float EPS = 1e-5f;

// Kernel launch configuration optimized for A800 (sm_80)
constexpr int THREADS_PER_BLOCK = 512;
constexpr int WARPS_PER_BLOCK = THREADS_PER_BLOCK / 32;
constexpr int THREADS_PER_WARP = 32;
constexpr int ELEMENTS_PER_THREAD = HIDDEN_SIZE / THREADS_PER_BLOCK;  // 8 elements per thread

// Kernel function declaration
__global__ void fused_add_rmsnorm_kernel(
    const nv_bfloat16* __restrict__ hidden_states,
    const nv_bfloat16* __restrict__ residual,
    const nv_bfloat16* __restrict__ weight,
    nv_bfloat16* __restrict__ output,
    int batch_size
);

// Host function declaration
torch::Tensor fused_add_rmsnorm(
    const torch::Tensor& hidden_states,
    const torch::Tensor& residual,
    const torch::Tensor& weight
);

// Helper function for device error checking
inline void checkCudaError(cudaError_t error, const char* operation) {
    if (error != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA error in ") + operation + ": " + 
                                cudaGetErrorString(error));
    }
}

// Helper function for tensor validation
inline void validateTensor(const torch::Tensor& tensor, const char* name, 
                          torch::Dtype expected_dtype, int expected_hidden_size = -1) {
    if (!tensor.is_cuda()) {
        throw std::runtime_error(std::string(name) + " must be on CUDA device");
    }
    if (tensor.dtype() != expected_dtype) {
        throw std::runtime_error(std::string(name) + " must have dtype bfloat16");
    }
    if (expected_hidden_size > 0 && tensor.size(-1) != expected_hidden_size) {
        throw std::runtime_error(std::string(name) + " must have hidden size " + 
                                std::to_string(expected_hidden_size) + ", got " + 
                                std::to_string(tensor.size(-1)));
    }
}

#include "kernel.h"

// Device helper for bfloat16 conversion
__device__ __forceinline__ float bfloat16_to_float(nv_bfloat16 val) {
    return __bfloat162float(val);
}

__device__ __forceinline__ nv_bfloat16 float_to_bfloat16(float val) {
    return __float2bfloat16(val);
}

// Warp-level shuffle primitive for efficient reduction
__device__ __forceinline__ float warpReduceSum(float val) {
    for (int offset = THREADS_PER_WARP / 2; offset > 0; offset /= 2) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }
    return val;
}

// Block-level reduction using warp-level primitives
__device__ __forceinline__ float blockReduceSum(float val, __shared__ float shared[]) {
    int lane = threadIdx.x & (THREADS_PER_WARP - 1);
    int warpId = threadIdx.x / THREADS_PER_WARP;

    // Warp-level reduction
    val = warpReduceSum(val);

    // Store warp results in shared memory
    if (lane == 0) {
        shared[warpId] = val;
    }
    __syncthreads();

    // Final reduction across warps (only warp 0 does this)
    if (warpId == 0) {
        float total = 0.0f;
        for (int i = 0; i < WARPS_PER_BLOCK; i++) {
            total += shared[i];
        }
        // Store the final result in shared[0]
        shared[0] = total;
    }

    // All threads synchronize to ensure shared[0] is ready
    __syncthreads();

    // All threads read the final result from shared[0]
    return shared[0];
}

__global__ void fused_add_rmsnorm_kernel(
    const nv_bfloat16* __restrict__ hidden_states,
    const nv_bfloat16* __restrict__ residual,
    const nv_bfloat16* __restrict__ weight,
    nv_bfloat16* __restrict__ output,
    int batch_size
) {
    // Shared memory for warp reduction results
    __shared__ float shared_sum[WARPS_PER_BLOCK];

    // Shared memory for caching input data (hidden_states + residual)
    __shared__ float shared_data[HIDDEN_SIZE];

    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int tid = threadIdx.x;

    // Calculate row pointers
    const nv_bfloat16* hs_row = hidden_states + batch_idx * HIDDEN_SIZE;
    const nv_bfloat16* res_row = residual + batch_idx * HIDDEN_SIZE;
    nv_bfloat16* out_row = output + batch_idx * HIDDEN_SIZE;

    // Phase 1: Load hidden_states + residual into shared memory and compute sum of squares
    float sum_sq = 0.0f;

    // Each thread processes ELEMENTS_PER_THREAD elements (8 for 4096/512)
    for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
        int idx = tid * ELEMENTS_PER_THREAD + i;
        float x = bfloat16_to_float(hs_row[idx]) + bfloat16_to_float(res_row[idx]);
        shared_data[idx] = x;
        sum_sq += x * x;
    }

    __syncthreads();

    // Reduce sum of squares across the block
    float total_sum_sq = blockReduceSum(sum_sq, shared_sum);

    // Compute RMS and inverse RMS
    float mean_sq = total_sum_sq / HIDDEN_SIZE;
    float inv_rms = rsqrtf(mean_sq + EPS);

    __syncthreads();

    // Phase 2: Normalize and multiply by weight using cached data
    for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
        int idx = tid * ELEMENTS_PER_THREAD + i;
        float x = shared_data[idx];
        float normalized = x * inv_rms;
        float w = bfloat16_to_float(weight[idx]);
        float final_val = normalized * w;
        out_row[idx] = float_to_bfloat16(final_val);
    }
}

// Host function to launch the kernel
torch::Tensor fused_add_rmsnorm(
    const torch::Tensor& hidden_states,
    const torch::Tensor& residual,
    const torch::Tensor& weight
) {
    // Validate inputs
    validateTensor(hidden_states, "hidden_states", torch::kBFloat16, HIDDEN_SIZE);
    validateTensor(residual, "residual", torch::kBFloat16, HIDDEN_SIZE);
    validateTensor(weight, "weight", torch::kBFloat16, HIDDEN_SIZE);

    // Check shapes match
    int64_t batch_size = hidden_states.size(0);
    if (residual.size(0) != batch_size) {
        throw std::runtime_error("residual batch size must match hidden_states");
    }
    if (weight.size(0) != HIDDEN_SIZE) {
        throw std::runtime_error("weight size must be " + std::to_string(HIDDEN_SIZE));
    }

    // Create output tensor
    auto options = torch::TensorOptions()
        .dtype(torch::kBFloat16)
        .device(hidden_states.device())
        .requires_grad(false);
    torch::Tensor output = torch::empty({batch_size, HIDDEN_SIZE}, options);

    // Get raw pointers
    const nv_bfloat16* hs_ptr = reinterpret_cast<const nv_bfloat16*>(hidden_states.data_ptr<torch::BFloat16>());
    const nv_bfloat16* res_ptr = reinterpret_cast<const nv_bfloat16*>(residual.data_ptr<torch::BFloat16>());
    const nv_bfloat16* weight_ptr = reinterpret_cast<const nv_bfloat16*>(weight.data_ptr<torch::BFloat16>());
    nv_bfloat16* out_ptr = reinterpret_cast<nv_bfloat16*>(output.data_ptr<torch::BFloat16>());

    // Configure kernel launch - optimized for A800
    dim3 grid(batch_size);
    dim3 block(THREADS_PER_BLOCK);

    // Launch kernel
    fused_add_rmsnorm_kernel<<<grid, block>>>(
        hs_ptr, res_ptr, weight_ptr, out_ptr, batch_size
    );

    // Check for launch errors
    checkCudaError(cudaGetLastError(), "kernel launch");

    // Synchronize to ensure completion
    checkCudaError(cudaDeviceSynchronize(), "kernel execution");

    return output;
}

#include <torch/extension.h>
#include "kernel.h"

// Forward declaration for the kernel function
torch::Tensor fused_add_rmsnorm(
    const torch::Tensor& hidden_states,
    const torch::Tensor& residual,
    const torch::Tensor& weight
);

// Main run function with proper error handling
torch::Tensor run(
    const torch::Tensor& hidden_states,
    const torch::Tensor& residual,
    const torch::Tensor& weight
) {
    try {
        // Validate all inputs are on the same device
        if (hidden_states.device() != residual.device()) {
            throw std::runtime_error("hidden_states and residual must be on the same device");
        }
        if (hidden_states.device() != weight.device()) {
            throw std::runtime_error("hidden_states and weight must be on the same device");
        }

        // Check if tensors are on CUDA
        if (!hidden_states.is_cuda()) {
            throw std::runtime_error("All tensors must be on CUDA device for this kernel");
        }

        // Check if tensors are contiguous
        if (!hidden_states.is_contiguous()) {
            throw std::runtime_error("hidden_states must be contiguous");
        }
        if (!residual.is_contiguous()) {
            throw std::runtime_error("residual must be contiguous");
        }
        if (!weight.is_contiguous()) {
            throw std::runtime_error("weight must be contiguous");
        }

        // Validate dtypes
        if (hidden_states.dtype() != torch::kBFloat16) {
            throw std::runtime_error("hidden_states must be bfloat16");
        }
        if (residual.dtype() != torch::kBFloat16) {
            throw std::runtime_error("residual must be bfloat16");
        }
        if (weight.dtype() != torch::kBFloat16) {
            throw std::runtime_error("weight must be bfloat16");
        }

        // Validate shapes
        if (hidden_states.dim() != 2) {
            throw std::runtime_error("hidden_states must be 2D tensor");
        }
        if (residual.dim() != 2) {
            throw std::runtime_error("residual must be 2D tensor");
        }
        if (weight.dim() != 1) {
            throw std::runtime_error("weight must be 1D tensor");
        }

        int64_t hidden_size = hidden_states.size(1);
        if (hidden_size != HIDDEN_SIZE) {
            throw std::runtime_error("hidden_size must be " + std::to_string(HIDDEN_SIZE) + 
                                   ", got " + std::to_string(hidden_size));
        }

        int64_t batch_size = hidden_states.size(0);
        if (residual.size(0) != batch_size) {
            throw std::runtime_error("residual batch size must match hidden_states");
        }
        if (weight.size(0) != HIDDEN_SIZE) {
            throw std::runtime_error("weight size must be " + std::to_string(HIDDEN_SIZE));
        }

        // Call the CUDA kernel
        return fused_add_rmsnorm(hidden_states, residual, weight);

    } catch (const std::exception& e) {
        throw std::runtime_error(std::string("Error in fused_add_rmsnorm: ") + e.what());
    }
}

// Pybind11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "Fused Add + RMSNorm kernel for A800 GPU";

    m.def("run", &run, "Execute fused add + RMSNorm operation",
          py::arg("hidden_states"),
          py::arg("residual"),
          py::arg("weight"));

    // Add module metadata
    m.attr("HIDDEN_SIZE") = HIDDEN_SIZE;
    m.attr("EPS") = EPS;
}
